Here's a modern MSTest test class for `DataFetcher` covering async patterns, timeouts, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, FakeHandler handler) CreateFetcher(
        HttpStatusCode statusCode = HttpStatusCode.OK,
        string content = "")
    {
        var handler = new FakeHandler(statusCode, content);
        var client = new HttpClient(handler);
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var (fetcher, _) = CreateFetcher(HttpStatusCode.OK, "hello world");

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var (fetcher, _) = CreateFetcher(HttpStatusCode.InternalServerError);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/error", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(HttpStatusCode.OK, "data",
            onSend: () => cts.Cancel());
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_AlreadyCancelledToken_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel();
        var (fetcher, _) = CreateFetcher();

        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesUrlToHandler()
    {
        var (fetcher, handler) = CreateFetcher(HttpStatusCode.OK, "ok");

        await fetcher.FetchAsync(
            "https://example.com/specific-path", _testContext.CancellationToken);

        Assert.AreEqual("https://example.com/specific-path",
            handler.LastRequestUri?.ToString());
    }

    // Fake handler — avoids needing a mocking library
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _statusCode;
        private readonly string _content;
        private readonly Action? _onSend;

        public Uri? LastRequestUri { get; private set; }

        public FakeHandler(HttpStatusCode statusCode, string content,
            Action? onSend = null)
        {
            _statusCode = statusCode;
            _content = content;
            _onSend = onSend;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            _onSend?.Invoke();
            cancellationToken.ThrowIfCancellationRequested();

            LastRequestUri = request.RequestUri;
            return Task.FromResult(new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            });
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(5000)]` + `_testContext.CancellationToken` passed to async calls |
| **Cancellation during flight** | `FakeHandler.onSend` triggers `cts.Cancel()` mid-request |
| **Pre-cancelled token** | Cancel the `CancellationTokenSource` before calling `FetchAsync` |
| **Exception testing** | `Assert.ThrowsExactlyAsync` for exact type, `Assert.ThrowsAsync` for base type (`OperationCanceledException` may be `TaskCanceledException`) |
| **Sealed class + ctor injection** | `TestContext` via constructor, class is `sealed` |
| **No mocking library needed** | Custom `HttpMessageHandler` gives full control |

The `_testContext.CancellationToken` is the critical piece — when `[Timeout]` fires, MSTest cancels that token, which propagates through your async call chain for cooperative cancellation instead of a hard thread abort.
